const BUNDLE_ID = "magister-dominion-token-sunlight-fix";
const TOKEN = "assets/magister-dominion-round-token.png";

function asset(bundle, localPath) {
  return bundle?.assets?.[localPath] ?? `modules/ai-patcher/inbox/${BUNDLE_ID}/${localPath}`;
}

function findMagister() {
  return game.actors.find((actor) =>
    actor.type === "npc" && (
      actor.getFlag("ai-patcher", "bundleId") === "magister-dominion-cr16" ||
      actor.getFlag("ai-patcher", "bundleId") === "magister-dominion-cr16-fixed" ||
      actor.getFlag("ai-patcher", "sourceTitle") === "Магистр Доминирования [CR 16]" ||
      String(actor.name ?? "").toLowerCase().includes("магистр доминирования")
    )
  );
}

function sunlightItem() {
  return {
    name: "Чувствительность к солнечному свету",
    type: "feat",
    img: "icons/magic/light/explosion-star-glow-yellow.webp",
    system: {
      description: {
        value: "<p>Находясь под прямым солнечным светом, Магистр получает <strong>20 урона излучением</strong> в начале своего хода. Пока он находится на солнечном свету, он совершает броски атаки и проверки характеристик с помехой.</p><p>Нажмите способность в начале хода Магистра, если он находится под солнцем: макрос сам нанесёт урон излучением.</p>",
        chat: ""
      },
      source: { revision: 1, rules: "2024", custom: "AI Patcher" },
      uses: { spent: 0, recovery: [], max: "" },
      activities: {},
      type: { value: "monster", subtype: "" },
      properties: []
    },
    effects: [],
    flags: {
      "ai-patcher": { bundleId: BUNDLE_ID },
      itemacro: {
        macro: {
          name: "Чувствительность к солнечному свету ItemMacro",
          type: "script",
          scope: "global",
          author: game.user.id,
          command: `const data = args?.[0] ?? {};
if (data.macroPass !== "postActiveEffects") return;
const selfActor = actor ?? data.workflow?.actor;
const selfToken = token?.document ?? canvas.tokens.placeables.find(t => t.actor?.id === selfActor?.id)?.document;
if (!selfActor) return;
const damage = 20;
if (game.modules.get("midi-qol")?.active && MidiQOL?.applyTokenDamage && selfToken) {
  const tokenObject = canvas.tokens.get(selfToken.id);
  await MidiQOL.applyTokenDamage([{ damage, type: "radiant" }], damage, new Set([tokenObject]), item, new Set([tokenObject]), { flavor: "Чувствительность к солнечному свету" });
} else {
  const hp = selfActor.system.attributes.hp;
  await selfActor.update({ "system.attributes.hp.value": Math.max(0, Number(hp.value ?? 0) - damage) });
}
await ChatMessage.create({
  speaker: ChatMessage.getSpeaker({ actor: selfActor, token: selfToken }),
  content: "<p><strong>Чувствительность к солнечному свету.</strong> Магистр получает <strong>20 урона излучением</strong>.</p>"
});`
        }
      },
      "midi-qol": {
        onUseMacroName: "Чувствительность к солнечному свету ItemMacro,[postActiveEffects]ItemMacro"
      }
    },
    ownership: { default: 0, [game.user.id]: 3 }
  };
}

export default async function patch({ dryRun, log, bundle }) {
  const actor = findMagister();
  if (!actor) throw new Error("Не найден Магистр Доминирования в текущем мире.");

  const tokenPath = asset(bundle, TOKEN);
  const oldSunItems = actor.items.filter((item) =>
    item.name === "Чувствительность к солнечному свету" ||
    item.getFlag("ai-patcher", "bundleId") === BUNDLE_ID
  );

  if (dryRun) {
    return {
      actor: actor.name,
      currentToken: actor.prototypeToken?.texture?.src,
      newToken: tokenPath,
      deleteOldSunItems: oldSunItems.length,
      addSunlightSensitivity: true
    };
  }

  log(`Updating Magister token and sunlight sensitivity: ${actor.name}`);
  if (oldSunItems.length) await actor.deleteEmbeddedDocuments("Item", oldSunItems.map((item) => item.id));

  await actor.update({
    "prototypeToken.texture.src": tokenPath,
    "prototypeToken.texture.fit": "contain",
    "prototypeToken.texture.scaleX": 1,
    "prototypeToken.texture.scaleY": 1,
    "prototypeToken.ring.enabled": true,
    "prototypeToken.ring.subject.scale": 0.98,
    "flags.ai-patcher.magisterTokenSunlightFix": true
  });
  await actor.createEmbeddedDocuments("Item", [sunlightItem()]);

  return {
    actor: actor.uuid,
    token: actor.prototypeToken.texture.src,
    added: "Чувствительность к солнечному свету"
  };
}
